import{c as a,Q as o,j as t,m as l}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"在 4GB 物理内存的机器上申请 8G 内存","description":"","frontmatter":{},"headers":[],"relativePath":"os/3_memory/linux_mem.md","filePath":"os/3_memory/linux_mem.md","lastUpdated":1779806814000}'),r={name:"os/3_memory/linux_mem.md"};function i(m,e,n,s,c,_){return o(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="在-4gb-物理内存的机器上申请-8g-内存" tabindex="-1">在 4GB 物理内存的机器上申请 8G 内存 <a class="header-anchor" href="#在-4gb-物理内存的机器上申请-8g-内存" aria-label="Permalink to &quot;在 4GB 物理内存的机器上申请 8G 内存&quot;">​</a></h1><blockquote><p>经典面试题：malloc 能成功吗？</p></blockquote><hr><h2 id="💡-答案-能" tabindex="-1">💡 答案：<strong>能</strong> <a class="header-anchor" href="#💡-答案-能" aria-label="Permalink to &quot;💡 答案：**能**&quot;">​</a></h2><p>虚拟内存机制让每个进程以为自己独占内存空间。默认情况下，Linux 允许 overcommit（过量分配）。</p><hr><h2 id="🔬-原理" tabindex="-1">🔬 原理 <a class="header-anchor" href="#🔬-原理" aria-label="Permalink to &quot;🔬 原理&quot;">​</a></h2><ul><li>进程看到的是虚拟地址空间（32位 ~4GB，64位超大）</li><li><code>malloc</code> 只是分配虚拟内存，不立即分配物理内存</li><li>真正使用时触发缺页中断，才分配物理页</li><li>即使物理内存不够，也可能通过 swap 换出</li></ul><blockquote><p>📖 深入：<a href="/os/3_memory/vmem.html">虚拟内存详解</a></p></blockquote>',9)])])}const h=a(r,[["render",i]]);export{u as __pageData,h as default};
